select count(*) from postgres.comments as c, postgres.postlinks as pl, postgres.posts as p, postgres.users as u, postgres.badges as b where u.id = b.userid and u.id = p.owneruserid and p.id = c.postid and p.id = pl.relatedpostid and c.creationdate<=timestamp '2014-09-13 20:12:15' and pl.linktypeid=1 and pl.creationdate>=timestamp '2011-09-03 21:00:10' and pl.creationdate<=timestamp '2014-07-30 21:29:52' and p.score>=0 and p.score<=23 and p.answercount>=0 and p.answercount<=4 and p.commentcount>=0 and p.commentcount<=10 and p.favoritecount<=9 and p.creationdate>=timestamp '2010-07-22 12:17:20' and p.creationdate<=timestamp '2014-09-12 00:27:12';
